settings.cardCss:
.floor-plan {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 12px;
  width: 100%;
  height: 100%;
  box-sizing: border-box;
}

.room {
  padding: 16px 12px;
  border-radius: 6px;
  background: #f5f5f5;
  border: 1px solid #ddd;
  position: relative;
  transition: all 0.3s;
}

.room-name {
  font-weight: 500;
  font-size: 14px;
  color: #333;
}

.room-info {
  font-size: 11px;
  color: #666;
  margin-top: 4px;
}

.badge {
  display: none;
  position: absolute;
  right: 12px;
  top: 50%;
  transform: translateY(-50%);
  background: #185FA5;
  color: white;
  padding: 3px 10px;
  border-radius: 12px;
  font-size: 11px;
  font-weight: 500;
}

/* Highlight active room dựa trên data-current */
.floor-plan[data-current="bedroom_1"] .room[data-zone="bedroom_1"],
.floor-plan[data-current="bedroom_2"] .room[data-zone="bedroom_2"],
.floor-plan[data-current="toilet"] .room[data-zone="toilet"] {
  background: #B5D4F4;
  border: 2px solid #185FA5;
}

.floor-plan[data-current="bedroom_1"] .room[data-zone="bedroom_1"] .room-name,
.floor-plan[data-current="bedroom_2"] .room[data-zone="bedroom_2"] .room-name,
.floor-plan[data-current="toilet"] .room[data-zone="toilet"] .room-name {
  color: #042C53;
}

.floor-plan[data-current="bedroom_1"] .room[data-zone="bedroom_1"] .badge,
.floor-plan[data-current="bedroom_2"] .room[data-zone="bedroom_2"] .badge,
.floor-plan[data-current="toilet"] .room[data-zone="toilet"] .badge {
  display: inline-block;
}
